mapper.select:
select
id, appid as appId, uamount, status, faitamount, paylogid, createtime, finishtime, rate, proof
from recharge
where appId = #{appId}

    and
    status = #{status}


    and
    createTime >= #{startCreateTime}


    and
    createTime <= #{endCreateTime}


    and
    finishTime >= #{startFinishTime}


    and
    finishTime <= #{endFinishTime}

order by CreateTime desc

    limit ${rowIndex},${limit}

select
count(*) as totalAllNum
from recharge
where appId = #{appId}

    and
    status = #{status}


    and
    createTime >= #{startCreateTime}


    and
    createTime <= #{endCreateTime}


    and
    finishTime >= #{startFinishTime}


    and
    finishTime <= #{endFinishTime}
